solution_code:
#include <iostream>

int main() {
    int age{};

    do {
        std::cout << "Enter your age (1-120): ";
        std::cin >> age;
    } while (age < 1 || age > 120);

    std::cout << "Age accepted: " << age << "\n";
    return 0;
}

